from lxml import etree
from urllib.request import urlopen


def process_soap_request(url, soap_envelope):
    parser = etree.XMLParser(dtd_validation=True)
    try:
        tree = etree.fromstring(soap_envelope, parser)
    except etree.XMLSyntaxError as e:
        return "Invalid XML: {error}".format(error=e)

    soap_body = tree.find("{http://schemas.xmlsoap.org/soap/envelope/}Body")

